UPDATE public.centros_custo cc
SET dimensao = s.dimensao,
    categoria_gerencial = s.categoria_gerencial,
    direto_indireto = s.direto_indireto,
    fixo_variavel = s.fixo_variavel,
    exige_contrato = s.exige_contrato,
    impacta_dre = s.impacta_dre,
    status_cadastro = s.status_cadastro,
    origem_cadastro = s.origem_cadastro,
    updated_at = now()
FROM src s
WHERE cc.codigo = s.codigo;

